// Código JavaScript para o nó Function no n8n

const defaultSettings = {
    executionOrder: $('Workflow ERRORS').first().json.executionOrder,
    saveExecutionProgress: $('Workflow ERRORS').first().json.saveExecutionProgress,
    errorWorkflow: $('Workflow ERRORS').first().json.wId_error,
    callerPolicy: $('Workflow ERRORS').first().json.callerPolicy,
    executionTimeout: $('Workflow ERRORS').first().json.executionTimeout,
    timeSavedPerExecution: $('Workflow ERRORS').first().json.timeSavedPerExecution
};

// Função para atualizar as configurações
function atualizarSettings(items) {
    return items.map(item => {
        const settings = item.json.settings || {};

        // Garante que os campos padrão sejam aplicados ou sobrescritos
        settings.executionOrder = defaultSettings.executionOrder;
        settings.saveExecutionProgress = defaultSettings.saveExecutionProgress;
        settings.errorWorkflow = defaultSettings.errorWorkflow;
        settings.callerPolicy = defaultSettings.callerPolicy;

        // Adiciona executionTimeout e timeSavedPerExecution apenas se não existirem
       /* if (settings.executionTimeout === undefined) {
            settings.executionTimeout = defaultSettings.executionTimeout;
        } 
        if (settings.timeSavedPerExecution === undefined) {
            settings.timeSavedPerExecution = defaultSettings.timeSavedPerExecution;
        } */

        // Retorna o item com as configurações atualizadas
        item.json.settings = settings;
        return item;
    });
}

// Obtém os itens do nó anterior
let items = $input.all();

// Atualiza as configurações de cada item
items = atualizarSettings(items);

// Retorna os itens atualizados
return items;

